import{_ as n,o as t,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung019.jpg",p="/images/uebung018.jpg",g=JSON.parse('{"title":"Übung Lektion 13","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung13.md","filePath":"lektionen/uebung13.md"}'),s={name:"lektionen/uebung13.md"};function h(o,e,d,l,m,u){return t(),r("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-13" tabindex="-1">Übung Lektion 13 <a class="header-anchor" href="#ubung-lektion-13" aria-label="Permalink to &quot;Übung Lektion 13&quot;">​</a></h1><p>A) Übersetzen Sie und verwandeln Sie in aktive Präsenssätze:</p><p>१. अग्निना गृहं दग्धम् । Ein Feuer hat das Haus verbrannt. अग्निर्गृहं दहति ।</p><p>२. बुद्धेन सत्यं बुद्धम् । Buddha ist zur Wahrheit erwacht. Buddha hat die Wahrheit erkannt. बुद्धः सत्यं बुध्यते / बोधति ।</p><p>३. बोध्या गौतमो मुक्तः । Die Erkenntnis hat Gautama erlöst. Durch die Erkenntnis wurde Gautama erlöst. बोधिर्गौतमं मुञ्चति ।</p><p>४. शूद्रा मूढाः । (2 Möglichkeiten) Die Śūdras / Śūdrafrauen sind verblendet. शूद्रा मुह्यन्ति ।</p><p>५. ब्राह्मणेन मोक्ष इष्टः । Der Brahmane wünschte Erlösung. ब्राह्मणो मोक्षमिच्छति ।</p><p>६. रामेण पुण्यं कृतम् । Rāma tat ein verdienstvolles Werk. Rāma tat Verdienstliches. रामः पुण्यं करोति ।</p><p>७. ऋषिभिः सत्यमेवोदितमित्युदितम् । Es ist gesagt, dass vedische Weise nur die Wahrheit gesagt haben. ऋषयः सत्य्मेव वदन्तीति वदन्ति ।</p><p>८. धर्मेण स्वर्गं नीतम् । Der Dharma hat in einen Himmel geführt. धर्मः स्वर्गं नयति ।</p><p>९. साधुनाधर्मो न कृतम् । Ein Heiliger hat nichts Unrechtes getan. साधुरधर्मं न करोति ।</p><p>१०. मन्त्रेण मोक्षो लब्धः । Mittels des Mantra hat man Erlösung erlangt. मन्त्रेण मोक्षं लभन्ते ।</p><p>११. कया रक्षिकयेयं बाला रक्षिता ॥ Was für ein Amulett hat dieses Mädchen beschützt? का रक्षिका बालां रक्षति ॥</p><p>B) Übersetzen Sie und verwandeln Sie in Passivsätze der Vergangenheit</p><p>१. राम इष्टमपि मोक्षं न लभते । Obwohl Rāma Erlösung wünscht, erlangt er sie nicht. रामेणेष्टो ऽपि मोक्षो न लब्धः ।</p><p>२. योज्ञो न मुञ्चति । Opfer erlöst nicht. यज्ञेन न मुक्तः ।</p><p>३. साधवो देवान्स्मरन्ति । Heilige vergegenwärtigen sich die Götter. साधुभिर्देवाः स्मृताः ।</p><p>४. पुण्यवान्पुत्रो देवान्यजते । Der tugendsame Sohn opfert den Göttern. पुण्यवता पुत्रेण देवा इष्टाः ।</p><p>५. सुखवान्क्षत्रियो धर्मं रक्षति । Der glückliche Kṣatriya hütet den Dharma. सुखवता क्षत्रियेण धर्मो रक्षितः ।</p><p>६. पुत्रवान्नरकं न गच्छति । Wer Söhne hat, kommt in keine Hölle. पुत्रवान्न्रकं न गतः ।</p><p>७. धर्मवती पापं न करोतीति गुरुर्वदति । Der Meister sagt, dass eine fromme Frau nichts Böses tut. धर्मवत्या पापं न कृतमिति गुरुणोदितम् ।</p><p>८. बुद्धिमन्तः सत्यवतो धर्मं प्र्च्छन्ति । Einsichtige befragen die, die die Wahrheit besitzen, über den Dharma. बुद्धिमद्भिः सत्यवन्तो धर्मं पृष्टाः ।</p><p>९. धर्मवन्तः फलवत्पुण्यं कुर्वन्ति । Religiöse Personen tun Verdienstvolles, das Frucht bringt. धर्मवद्भिः फलवत्पुण्यं कृतम् ।</p><p>१०. ब्राह्मणा गुणवतः पुत्रानिच्छन्ति । Brahmanen wünschen sich vorzügliche Söhne. ब्राह्मणैर्गुणवन्तः पुत्रा इष्टाः ।</p><p>११. कयृग्वेदं शृण्वन्ति । Welche Männer hören den Ṛgveda? कैरृग्वेदः श्रुतः ।</p><p>१२. किमीश्वरः सृजति । Was erschafft der HERR? किमीश्वरेण सृष्टम् ।</p><p>१३. साधुः कृतं पापं सहते । Ein Heiliger erträgt ihm zugefügtes Übel. साधुना कृतं पापं सोढम् ।</p><p>१४. पार्थिवो धनमिच्छतीति नीचा मन्यन्ते । Niedrige denken, dass Herrscher Reichtum wünschen. पार्थिवेन धनमिष्टमिति नीचैर्मतम् ।</p><p>१५. नैवासुरो जयतीत्यृषयः पश्यन्ति । Die vedischen Weisen sehen,  dass der Dämon auf keinen Fall siegt. नैवासुरेण जितमित्यृषिभिर्दृष्टम् ।</p><p>१६. ब्राह्मणाः किं पिबन्ति खादन्ति च ॥ Was essen und trinken Brahmanen? ब्राह्मणैः किं पीतं खादितं च ॥</p><p><img src="'+i+'" alt=""><br> Abb.: अग्निर्गृहं दहति ।<br> Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: lecercle. -- <a href="http://www.flickr.com/photos/lecercle/2471082860/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lecercle/2471082860/</a>. -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, Share alike)]</p><p>A) Übersetzen Sie folgende Sätze.</p><p>B) Setzen Sie die Sätze Übung A) ins Passiv</p><p>C) Bilden Sie zu den Sätzen Übung A) eine PPP-Konstruktion</p><p>१. रामो मार्गेण ग्रामं गच्छति । Rāma geht auf dem Weg ins Dorf. रामेण मार्गेण ग्रामं गम्यते । रामेण मार्गो ग्रामं गम्यते । रामो मार्गेण ग्रामं गतः । रामेण मार्गो ग्रामं गतम् ।</p><p>२. नरा धनेन सुखमिच्छन्ति । Menschen wünschen sich Glück durch Reichtum. नरैर्धनेन सुखमिष्यते । सुखमिष्टम् ।</p><p>३. नरः पुत्रेण नगरं पद्यते । Der Mann geht mit seinem Sohn in die Stadt. नरेण पुत्रेण (सह) नगरं पद्यते । नरः पुत्रेण (सह) नगरं पन्नः ।</p><p>४. देवो लोकान्सृजति । Gott erschafft die Welten. देवेन लोकाः सृज्यन्ते । सृष्टाः ।</p><p>५. बाला जलं पिबति । Das Mädchen trinkt Wasser. बालया जलं पीयते । पीतम् ।</p><p>६. कवयो धनं लुभ्यन्ति । Dichter begehren Reichtum. कविबिर्धनं लुभ्यते । लुब्धम् ।</p><p>७.  बलवान्क्षत्रियः शूद्राञ्जयति । Der mächtige Kṣatriya besiegt die Śūdras. बल्वता क्षत्रियेण शत्रवो जीयन्ते । जिताः ।</p><p>८. गुणवान्द्विष्टमपि शत्रुं न युध्यते ।  Jemand Tugendhaftes bekämpft seinen Feind nicht, auch wenn dieser ihm verhasst ist. गुणवता द्विष्तो ऽपि शत्रुर्न युध्यते । युद्धः ।</p><p>९. अधर्मः क्रोधश्च द्वेषश्च लोभश्चेत्यृषिर्वदति । Der vedische Weise sagt, das Zorn, Hass und Gier Unrecht sind. अधर्मः क्रोधश्च द्वेषश्च लोभश्चेत्यृषिणोद्यते । लोभश्चेत्यृषिणोदितम् ।</p><p>१०. बाला अन्नेन बलमाप्नुवन्ति । Knaben werden durch Essen stark. बालैरन्नेन बलमाप्यते । बालाभिरन्नेन बलमाप्यते । बलमाप्तम् ।</p><p>११. बुद्धिमन्तः सत्येन मोक्षं लभन्ते । Einsichtige erlangen durch die Wahrheit die Erlösung. बुद्धिमद्भिः सत्येन मोक्षो लभ्यते । लब्धः ।</p><p>१२. इमाः साध्व्यः पापं सहन्ते । Diese heiligen Frauen ertragen das Übel. इमाभिः साध्वीभिः पापं सह्यते । सोढम् ।</p><p>१३. कां देवतामृषिः पश्यति । Welche Gottheit sieht der Ṛṣi? का देवतर्षिना दृश्यन्ते । दृष्टा ।</p><p>१४. कान्देवान्ब्राह्मणक्षत्रियवैश्या यजन्ते । Welchen Göttern opfern Brahmanen, Katriyas und Vaśyas? के देवा ब्राह्मणक्षत्रियवैश्यैरिज्यन्ते । ब्राह्मणक्षत्रियवैश्यैरिष्टाः ॥</p><p>D) Aus welchen Lautverbindungen können folgende Sandhiformen entstanden sein? Geben Sie alle Möglichkeiten an:</p><p>1. -a vor Vokal (außer a-): -as</p><p>2. -ā- : -a + -a/-ā  -ā + a-/ā-</p><p>3. -ā vor Vokal: -ās</p><p>4. -ā vor stimmhaften Konsonanten: -ās</p><p>5. -ī-: -i + i-/ī-, -ī + i-/-ī</p><p>6. -ū-: -u/-ū + u-/ū-</p><p>7. -ṝ-: -ṛ/-ṝ + ṛ-/ṝ-</p><p>8. -e-: -a/-ā + i-/ī-</p><p>9. -e vor Avagraha: -e + a-</p><p>10. -o-: -a/-ā + u-/ū-</p><p>11. -o vor Avagraha: -o</p><p>12. -o vor stimmhaften Konsonanten -as</p><p>13. -ai-: -a/-ā + e-/ai-</p><p>14. -au-: -a/-ā + e-/ai-</p><p>15. -y vor Vokal: -i/-ī</p><p>16. -v vor Vokal: -u/-ū</p><p>17. -r vor Vokal: -ṛ/-ṝ</p><p>18. -ay vor Vokal: -e</p><p>19. -av vor Vokal: -o</p><p>20. -ar-: -a/-ā + ṛ-/ṝ-</p><p>21. -ir vor Vokal oder stimmhaftem Konsonanten: -is</p><p>22. -īr vor Vokal oder stimmhaftem Konsonanten: -īs</p><p>23. -ur vor Vokal oder stimmhaftem Konsonanten: -us</p><p>24. -ūr vor Vokal oder stimmhaftem Konsonanten: -ūs</p><p>25. -er vor Vokal oder stimmhaftem Konsonanten: -es</p><p>26. -or vor Vokal oder stimmhaftem Konsonanten: -os</p><p>27. -air vor Vokal oder stimmhaftem Konsonanten: -ais</p><p>28. -aur vor Vokal oder stimmhaftem Konsonanten: -aus</p><p>29. -ñj-: -n + j-</p><p>30. -ñś-: -n + ś</p><p>31. -ñch-: -n + ch-</p><p>32. -ṇḍ(h)-: -n + ḍ(h)-</p><p>33. -śc-: -s + c-</p><p>34. -ṣṭ-: -s + t-</p><p>35. -st(h)-: -s + t(h)-</p><p>36. Anusvara vor Konsonant: -m</p><p>37. -ṃśc-: -n + c-</p><p>38. -ṃṣṭ-: -n + ṭ-</p><p>39 -mst-: -n + t-</p><p>E) Übersetzen Sie ins Sanskrit:</p><p>1. Die Göttin war erzürnt. देवी कुपिता । देव्या कुपितम्</p><p>2. Śūdras sind in einen Himmel gelangt. शूद्रैः स्वर्ग आप्तः । स्वर्गो ऽष्टः ।</p><p>3. Die Bauern sind den Weg gegangen. कर्षकैर्मार्गो गतः । कर्षका मार्गं गताः ।</p><p>4. Durch die Buddhalehre wurden die Leute befreit. धर्मेण जना मुक्ताः ।</p><p>5. Der Sohn tanzte. पुत्रेण नृत्तम् ।</p><p>6. Das Amulett hat den Lehrer beschützt. रक्षिकया गुरू रक्षितः ।</p><p>7. Ein Brahmane hat keine Unwahrheit gesagt. ब्राह्मणेनानृतं नोदितम् ।</p><p>8. Śūdrafrauen haben die Göttin mit Opfern verehrt. शूद्राभिर्देवीष्टा ।</p><p>9. Buddha ist zur Wahrheit erwacht = Buddha hat die Wahrheit erkannt. बुद्धेन सत्यं बुद्धम् । बुद्धः सत्यं बुद्धः ।</p><p>10. Die vedischen Weisen haben die Śruti gehört. ऋषिभिः श्रुतिः श्रुता ।</p><p>11. Die Opferpriester haben den Soma gepresst. यजकैः सोमः सुतः ॥</p><p><img src="'+p+'" alt=""><br> Abb.: बाला जलं पिबति । बालया जलं पीयते ।<br> सरोजिनी नगर, Delhi = दिल्ली<br> [Bildquelle: Prato9x. -- <a href="http://www.flickr.com/photos/55163494@N00/209096948/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/55163494@N00/209096948/</a>. -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',102)])])}const k=n(s,[["render",h]]);export{g as __pageData,k as default};
